"use strict";

(function () {
    function defaultParseApiError(rawText, statusCode, statusText) {
        const fallback = Number.isFinite(statusCode)
            ? String(statusCode) + " " + String(statusText || "").trim()
            : "Ошибка запроса.";

        if (!rawText) {
            return fallback.trim();
        }

        try {
            const payload = JSON.parse(rawText);
            if (payload && typeof payload.detail === "string" && payload.detail.trim().length > 0) {
                return payload.detail;
            }

            if (payload && typeof payload.error === "string" && payload.error.trim().length > 0) {
                return payload.error;
            }

            if (payload && typeof payload.title === "string" && payload.title.trim().length > 0) {
                return payload.title;
            }
        } catch {
            return rawText;
        }

        return rawText;
    }

    function createApiClient(options) {
        const settings = options || {};
        const fetchImpl = settings.fetchImpl || fetch;
        const parseApiError = settings.parseApiError || defaultParseApiError;
        const rulesApi = settings.rulesApi || "/api/sla/rules";
        const violationsApi = settings.violationsApi || "/api/sla/violations";
        const runApi = settings.runApi || "/api/sla/run";

        async function request(url, options) {
            const requestOptions = options || {};
            const hasBody = typeof requestOptions.body === "string";
            const response = await fetchImpl(url, {
                credentials: "include",
                ...requestOptions,
                headers: {
                    Accept: "application/json",
                    ...(hasBody ? { "Content-Type": "application/json" } : {})
                }
            });

            if (!response.ok) {
                let bodyText = "";
                try {
                    bodyText = await response.text();
                } catch {
                    bodyText = "";
                }

                throw new Error(parseApiError(bodyText, response.status, response.statusText));
            }

            if (response.status === 204) {
                return null;
            }

            const responseText = await response.text();
            if (!responseText) {
                return null;
            }

            return JSON.parse(responseText);
        }

        async function getRules() {
            return request(rulesApi, { method: "GET" });
        }

        async function saveRules(items) {
            return request(rulesApi, {
                method: "PUT",
                body: JSON.stringify({
                    items: Array.isArray(items) ? items : []
                })
            });
        }

        async function getViolations(includeResolved) {
            const includeResolvedValue = includeResolved ? "true" : "false";
            return request(violationsApi + "?includeResolved=" + includeResolvedValue, {
                method: "GET"
            });
        }

        async function runMonitoring(sendNotifications) {
            const sendNotificationsValue = sendNotifications ? "true" : "false";
            return request(runApi + "?sendNotifications=" + sendNotificationsValue, {
                method: "POST"
            });
        }

        async function saveViolationReason(violationId, payload) {
            return request(violationsApi + "/" + encodeURIComponent(violationId) + "/reason", {
                method: "PUT",
                body: JSON.stringify(payload || {})
            });
        }

        return {
            request: request,
            getRules: getRules,
            saveRules: saveRules,
            getViolations: getViolations,
            runMonitoring: runMonitoring,
            saveViolationReason: saveViolationReason
        };
    }

    const exportsObject = {
        createApiClient: createApiClient
    };

    if (typeof window !== "undefined") {
        window.SlaPageApi = exportsObject;
    }

    if (typeof module !== "undefined" && module.exports) {
        module.exports = exportsObject;
    }
})();

/* Source: sla-page-rules.js */
"use strict";

(function () {
    function createDraftRule() {
        return {
            purchaseTypeCode: "",
            warningDaysBeforeDue: 2,
            isActive: true,
            description: ""
        };
    }

    function renderRulesMarkup(rules, helpers) {
        if (!Array.isArray(rules) || rules.length === 0) {
            return "<tr><td colspan=\"5\">Правила SLA не заданы. Добавьте хотя бы одно правило.</td></tr>";
        }

        return rules
            .map(function (rule, index) {
                return (
                    "<tr>" +
                    "<td><input type=\"text\" data-rule-field=\"purchaseTypeCode\" data-rule-index=\"" + index + "\" value=\"" + helpers.escapeHtml(rule.purchaseTypeCode || "") + "\" /></td>" +
                    "<td><input type=\"number\" min=\"0\" max=\"30\" data-rule-field=\"warningDaysBeforeDue\" data-rule-index=\"" + index + "\" value=\"" + Number(rule.warningDaysBeforeDue || 0) + "\" /></td>" +
                    "<td style=\"text-align:center\"><input type=\"checkbox\" data-rule-field=\"isActive\" data-rule-index=\"" + index + "\" " + (rule.isActive ? "checked" : "") + " /></td>" +
                    "<td><input type=\"text\" data-rule-field=\"description\" data-rule-index=\"" + index + "\" value=\"" + helpers.escapeHtml(rule.description || "") + "\" /></td>" +
                    "<td><button type=\"button\" class=\"dashboard-refresh\" data-remove-rule-index=\"" + index + "\">Удалить</button></td>" +
                    "</tr>"
                );
            })
            .join("");
    }

    function collectRulesFromRows(rows) {
        const sourceRows = Array.isArray(rows) ? rows : [];

        return sourceRows
            .map(function (row) {
                const purchaseTypeCodeInput = row.querySelector("[data-rule-field=\"purchaseTypeCode\"]");
                const warningDaysInput = row.querySelector("[data-rule-field=\"warningDaysBeforeDue\"]");
                const isActiveInput = row.querySelector("[data-rule-field=\"isActive\"]");
                const descriptionInput = row.querySelector("[data-rule-field=\"description\"]");

                if (!purchaseTypeCodeInput || !warningDaysInput || !isActiveInput || !descriptionInput) {
                    return null;
                }

                const warningDaysBeforeDue = Number(warningDaysInput.value || "0");
                return {
                    purchaseTypeCode: String(purchaseTypeCodeInput.value || "").trim(),
                    warningDaysBeforeDue: Number.isFinite(warningDaysBeforeDue) ? warningDaysBeforeDue : 0,
                    isActive: !!isActiveInput.checked,
                    description: String(descriptionInput.value || "").trim() || null
                };
            })
            .filter(function (item) {
                return item && item.purchaseTypeCode.length > 0;
            });
    }

    const exportsObject = {
        createDraftRule: createDraftRule,
        renderRulesMarkup: renderRulesMarkup,
        collectRulesFromRows: collectRulesFromRows
    };

    if (typeof window !== "undefined") {
        window.SlaPageRules = exportsObject;
    }

    if (typeof module !== "undefined" && module.exports) {
        module.exports = exportsObject;
    }
})();

/* Source: sla-page-violations.js */
"use strict";

(function () {
    function renderViolationsMarkup(violations, helpers) {
        if (!Array.isArray(violations) || violations.length === 0) {
            return "<tr><td colspan=\"8\">Открытых нарушений SLA не найдено.</td></tr>";
        }

        return violations
            .map(function (violation) {
                const severityBadgeClass = violation.severity === "Overdue"
                    ? "dashboard-task__priority--high"
                    : "dashboard-task__priority--medium";
                const statusLabel = violation.isResolved ? "Закрыто" : "Открыто";
                return (
                    "<tr data-violation-id=\"" + violation.id + "\">" +
                    "<td><span class=\"dashboard-task__priority " + severityBadgeClass + "\">" + helpers.escapeHtml(helpers.localizeSeverity(violation.severity)) + "</span></td>" +
                    "<td>" + helpers.formatDate(violation.dueDate) + "</td>" +
                    "<td>" + helpers.escapeHtml(violation.title || "") + "</td>" +
                    "<td>" + helpers.escapeHtml(violation.recipientEmail || "") + "</td>" +
                    "<td><input type=\"text\" data-violation-field=\"reasonCode\" value=\"" + helpers.escapeHtml(violation.reasonCode || "") + "\" placeholder=\"например: DOC_DELAY\" /></td>" +
                    "<td><input type=\"text\" data-violation-field=\"reasonComment\" value=\"" + helpers.escapeHtml(violation.reasonComment || "") + "\" placeholder=\"Комментарий\" /></td>" +
                    "<td>" + statusLabel + "</td>" +
                    "<td><button type=\"button\" class=\"dashboard-refresh\" data-save-reason-id=\"" + violation.id + "\">Сохранить</button></td>" +
                    "</tr>"
                );
            })
            .join("");
    }

    function buildViolationReasonPayload(row) {
        if (!row || typeof row.querySelector !== "function") {
            return {
                reasonCode: "",
                reasonComment: null
            };
        }

        const reasonCodeInput = row.querySelector("[data-violation-field=\"reasonCode\"]");
        const reasonCommentInput = row.querySelector("[data-violation-field=\"reasonComment\"]");

        return {
            reasonCode: String(reasonCodeInput && reasonCodeInput.value ? reasonCodeInput.value : "").trim(),
            reasonComment: String(reasonCommentInput && reasonCommentInput.value ? reasonCommentInput.value : "").trim() || null
        };
    }

    const exportsObject = {
        renderViolationsMarkup: renderViolationsMarkup,
        buildViolationReasonPayload: buildViolationReasonPayload
    };

    if (typeof window !== "undefined") {
        window.SlaPageViolations = exportsObject;
    }

    if (typeof module !== "undefined" && module.exports) {
        module.exports = exportsObject;
    }
})();

